		int slot = existingSlot(var.getName());
		if (slot < 0) {
			return null;
		}
		long[] accepted = new long[args.size() - 1];
		Value[] acceptedValues = new Value[args.size() - 1];
		int acceptedSize = 0;
		for (int i = 1; i < args.size(); i++) {
			ValueExpr candidate = args.get(i);
			Value value;
			if (candidate instanceof ValueConstant) {
				value = ((ValueConstant) candidate).getValue();
			} else if (candidate instanceof Var && ((Var) candidate).hasValue()) {
				value = ((Var) candidate).getValue();
			} else {
				return null;
			}
			long id = idOf(value);
			if (id == UNKNOWN) {
				return null;
			}
			accepted[acceptedSize] = id;
			acceptedValues[acceptedSize] = value;
			acceptedSize++;
		}
		if (acceptedSize == 0) {
			return row -> false;
		}
		return new ValueSetFilter(source, slot,
				acceptedSize == accepted.length ? accepted : Arrays.copyOf(accepted, acceptedSize),
				acceptedSize == acceptedValues.length ? acceptedValues
						: Arrays.copyOf(acceptedValues, acceptedSize),
				(assuredMask & 1L << slot) == 0L);
